<template>
  <div class="container">
    <div class="game">
      <div class="game-title">百化分</div>
      <!-- <p>{{ (seconds/100).toFixed(2) }} s</p> -->
      <div v-if="!gamestart">
        <table class="mytable p2f" v-for="tab in 3">
          <tr v-for="col in 8">
            <td class="fct-td">
              {{getfct(col-1+((tab-1)*8))}}
            </td>
             <td class="pct-td">
              {{getpct(col-1+((tab-1)*8))}}
            </td>
          </tr>
        </table>
      </div>

      <div class="questionbox" v-else>
        <div class="ques">
          {{getQu(ques)}}
        </div>
        <div class="option nocopy" v-for="(option, index) in options" @click="selectOption($event, option)" :id="`o`+option">
          {{String.fromCharCode(65+index)}}.{{getOp(option)}}
        </div>
      </div>
      <div class="game-btn" @click="startgame">
        {{gamestart ? "结束训练" : "开始训练"}}
      </div>
    </div>
  </div>
</template>

<script>
import {ref,onUnmounted} from 'vue'

export default {
  name: 'Pct2Fct',
  setup() {
    const gamestart = ref(false)

    let quesflag = 0

    let canselect = false

    const ques = ref(0)

    const options = ref([])
    //模式, 默认0：练习模式，1:冒险模式 ,2:限时模式
    let pattern = 0

    const fdata = ref([[1,2],[1,3],[1,4],[1,5],[1,6],[1,7],[1,8],[1,9],[1,10],[1,11],[1,12],[1,13],[1,14],[1,15],[1,16],[1,17],[1,18],[1,19],[1,20],[3,8],[5,8],[7,8],[2,7],[3,7]])

    const getfct = (index) => {
      return fdata.value[index][0]+'/'+fdata.value[index][1]
    }

    const getpct = (index) => {
      return (fdata.value[index][0]*100/fdata.value[index][1]).toFixed(2)*100/100 + '%'
    }

    const getAscll = (index) => {
      return String.fromCharCode(index)
    }

    const setoptions = (index) => {
      options.value = []
      var array = []
      array.push(index)
      for(var i=0; i < 3; i++){
        var as = Math.floor(Math.random()*(24));
        if (array.indexOf(as) == -1) {
          array.push(as)
        }else{
          i--
        }
      }
      options.value = shuffleNumber(array)
    }

    const startgame = () => {
      gamestart.value =! gamestart.value
      if(gamestart.value){
        refreshquestion()
      }
    }

    const refreshquestion = () => {
      canselect = true
      quesflag = Math.round(Math.random())
      ques.value = Math.floor(Math.random()*(24))
      console.log(ques.value)
      setoptions(ques.value)
      startTimer()
    }



    const getQu = (index) => {
      console.log(index,quesflag)
      switch(quesflag){
        case 0 :
          return getfct(index)
        case 1 :
          return getpct(index)
      }
    }

    const getOp = (index) => {
      switch(quesflag){
        case 0 :
          return getpct(index)
        case 1 :
          return getfct(index)
      }
    }

    const selectOption = (e, option) => {

      stopTimer()
      if(canselect){
        canselect = false
        var dom = e.currentTarget
        var rightdom = document.getElementById("o"+ques.value)
        if(option == ques.value){
          console.log('right')
          dom.style.backgroundColor = '#b0ffbb'
        }else{
          rightdom.style.backgroundColor = '#b0ffbb'
          dom.style.backgroundColor = '#ffb0b0'
        } 
        if (pattern == 0) {

          setTimeout(function(){
            rightdom.style.backgroundColor = '#eee'
            dom.style.backgroundColor = '#eee'
            refreshquestion()
          },3000)
        }
      }
      
    }

    function shuffleNumber(array) {
      for (let i = array.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [array[i], array[j]] = [array[j], array[i]]; // 使用 ES6 的解构交换元素
      }
      return array;
    }

    const seconds = ref(0);
    let interval;

    const startTimer = () => {
      seconds.value = 0
      interval = setInterval(() => {
        seconds.value += 1;
      }, 10);
    };  

    const stopTimer = () => {
      clearInterval(interval);
    };

    onUnmounted(() => {
      clearInterval(interval); // 清除定时器，防止内存泄漏
    });



    return {
      fdata,
      getfct,
      getpct,
      gamestart,
      getAscll,
      options,
      startgame,
      ques,
      getQu,
      getOp,
      selectOption,
      seconds
    } 
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
  .container {
    margin: 20px 30px;
    padding: 10px 20px ;
    border: var(--box-border);
    border-radius:12px;
    display: flex;
    flex-direction: column;
    text-align: center;
    align-items: center;
    background-color: var(--box-bgc);
  }

  .mytable.p2f {
    display: inline-block;
    margin: 1rem 0.5rem 0 0.5rem;
  }

  .mytable.p2f > th,td {
    padding: 4px 0;
    width: 70px;
  }

  .fct-td {
    width: 50px;
    font-weight: 500;
  }

  .questionbox{
    margin: 1rem;
    
    width: 300px;
/*    border: 1px solid #000;*/

  }
  .ques {
    padding: 1.5rem;
    font-size: 2rem;
    display: block;
  }

  .option {
    padding: 10px 7px;
    text-align: left;
    display: inline-block;
/*    transform: translateX(25%);*/
    width: calc(50% - 44px);
/*    border: 1px solid #555;*/
    background-color: #eee;
    border-radius: 8px;
    margin: 10px 14px;
    color: #363636;
  }

  .option:active {
    background-color: #bdddff;
  }

  @media (any-hover:hover){
    .option:hover {
      background-color: #bdddff;
    }
  }
</style>

